-- kb-doc/system-standards/operating-model
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$kb-doc/system-standards/operating-model$T$,
  $T${"blocks":[{"type":"Hero","props":{"lede":"How an agent works a ticket from open to close. Seven phases (OBSERVE → THINK → PLAN → BUILD → EXECUTE → VERIFY → LEARN), five tier gates (E1-E5), atomic ISC discipline, mandatory SUMMARY close. This is the *behavioral* contract — what the agent does on every ticket, not what the system *is*.","title":"MyJarvis — Operating Model · 7-Phase Algorithm","eyebrow":"SYSTEM · OPERATING MODEL"}},{"type":"ImageBlock","props":{"alt":"MyJarvis operating-model diagram — 7 phase cards and tier gate matrix","src":"https://{{r2_public_host}}/assets/operating-model-v1-20260513-144358.png","caption":"*Generated 2026-05-13 with Nano Banana. Color-coded phase cards + tier-gate matrix. One phase card has a Banana rendering glitch — the exact phase names are listed in the table below.*"}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"What each phase produces","eyebrow":"01 — THE 7 PHASES"}},{"type":"DataTable","props":{"rows":[["01","**OBSERVE**","Read the ticket Problem + Constraints. Run probes. Surface what's there.","Notes; nothing committed yet."],["02","**THINK**","Form a Vision. Identify Decisions you'll have to make. Note Unknowns.","Vision + Decisions log."],["03","**PLAN**","Write Criteria (ISCs — atomic, binary, single-probe). Sequence the work.","ISC checklist."],["04","**BUILD**","Implement. Edit files. Apply migrations. Generate assets.","Code/data changes (not yet shipped)."],["05","**EXECUTE**","Run the build / push / `ship` / `apply_migration`. Make it real.","Shipped change."],["06","**VERIFY**","Run each ISC's probe. Tick boxes. Log evidence. Iterate if a probe fails.","ISCs done = total."],["07","**LEARN**","Capture decisions + learnings. Ask: promote anything to a KB page?","Memories + (maybe) new KB page."]],"headers":["#","Phase","What you do","Output"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"What each tier requires before THINK","eyebrow":"02 — TIER GATES"}},{"type":"P","props":{"body":"Tier sets the rigor of the ticket. Default tier is E1 — almost nothing required. Upgrade as scope grows."}},{"type":"DataTable","props":{"rows":[["**E1**","Problem only","—","Single chat thread / short task"],["**E2**","Problem + Vision + Goal","small change set","1-2 file edit / single feature flag"],["**E3**","Add Out-of-Scope + Constraints + Criteria","design notes","Multi-file build / doctrine change"],["**E4**","Add Test Strategy + Features + Decisions","design doc","Architectural change / cross-domain"],["**E5**","Full ISA-12 (all 12 sections)","formal RFC","Platform-level / migration / major refactor"]],"headers":["Tier","Required ISA-12 sections","Required artifacts","Typical scope"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Every algorithm response ends with this","eyebrow":"03 — MANDATORY CLOSE"}},{"type":"QuoteBlock","props":{"body":"**SUMMARY** — phase X/7, ISCs Y/Z done, one-line next.\n\nMandatory at the end of every response while the ticket is at tier ≥ E2. If you don't write the SUMMARY, the next agent picking up the ticket can't tell where you stopped."}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"See the whole picture","eyebrow":"04 — CROSS-LINKS"}},{"type":"P","props":{"body":"Sister diagrams: [System Architecture](/kb-doc/mj-os/system-diagram) · [Data Flows](/kb-doc/mj-os/data-flows) · [Operating Model](/kb-doc/mj-os/operating-model) · [Knowledge Taxonomy](/kb-doc/mj-os/knowledge-taxonomy) · [Persona Stack](/kb-doc/mj-os/persona-stack)."}},{"type":"Footer","props":{"line1":"Operating model — locked 2026-05-13. 7 phases, 5 tiers, 1 close format.","line2":"Full spec: `mjos-algorithm` skill in `~/.claude/skills/mjos-algorithm/SKILL.md`."}}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- kb-doc/system-standards/persona-stack
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$kb-doc/system-standards/persona-stack$T$,
  $T${"blocks":[{"type":"Hero","props":{"lede":"The agent layer. Six personas — Jarvis, Atlas, Ben, Nova, Emma, Iris — each with a distinct voice and label. One operating model (R&D today for all six). Shared memory. The persona an {{operator_name}} terminal addresses is determined by the first word of the first prompt.","title":"MyJarvis — Persona Stack & Session Lifecycle","eyebrow":"SYSTEM · PERSONA STACK"}},{"type":"ImageBlock","props":{"alt":"MyJarvis persona stack diagram — six personas, session lifecycle, ticket handoff, shared memory","src":"https://{{r2_public_host}}/assets/persona-stack-v1-20260513-144358.png","caption":"*Generated 2026-05-13 with Nano Banana. Six persona cards, session lifecycle chain, ticket-handoff + shared-memory panels.*"}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Identity + voice mapping","eyebrow":"01 — THE 6 PERSONAS"}},{"type":"P","props":{"body":"Activation: the **first word** of your first prompt in a fresh terminal. Case-insensitive. If no match, default is Jarvis."}},{"type":"DataTable","props":{"rows":[["**Jarvis** (default)","`echo`","`am_echo`","Jarvis","R&D — full cycle"],["**Atlas**","`onyx`","`am_onyx`","Atlas","R&D — full cycle"],["**Ben**","`fable`","`bm_fable`","Ben","R&D — full cycle"],["**Nova**","`nova`","`af_nova`","Nova","R&D — full cycle"],["**Emma**","`alloy`","`bf_emma`","Emma","R&D — full cycle"],["**Iris**","`shimmer`","`af_aoede`","Iris","R&D — full cycle"]],"headers":["Persona","MCP voice","Kokoro voice ID","`agent_name` label","Role today"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"How state hands off","eyebrow":"02 — SESSION LIFECYCLE"}},{"type":"P","props":{"body":"A terminal opens. A persona locks. State hydrates from Neon. State files mark the terminal. State files get cleaned up on close."}},{"type":"DataTable","props":{"rows":[["1","User opens terminal","Fresh session."],["2","First word matches persona (or default Jarvis)","`DetectAgent.hook` writes `.claude/state/active-agent.<sid>`"],["3","Agent runs psql hydration query","Reads `agents`, `tickets`, `memories` rows for this persona."],["4","Agent opens (or resumes) a ticket","INSERTs/UPDATEs `tickets`. Writes `.claude/state/active-ticket.<sid>`. `agents.current_ticket_id` updated."],["5","Statusline reads both state files","Renders `● <Persona> → MJOS-XXX — Title` on line 1."],["6","Every 4 turns, `SaveSessionMemory.hook` nudges","Agent INSERTs a `session_log` memory."],["7","Session ends — `SessionCleanup.hook` fires","Deletes the per-session state files. Sweeps stragglers >7 days old."]],"headers":["Step","What fires","Where state goes"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Cross-session continuity","eyebrow":"03 — TICKET HANDOFF"}},{"type":"P","props":{"body":"Three pieces of state agree on which ticket a persona is on:"}},{"type":"DataTable","props":{"rows":[["**`agents.current_ticket_id`** (Neon column)","The cross-session 'last known' pointer. Most recent session wins.","Persistent until updated"],["**`.claude/state/active-ticket.<sid>`** (file)","Per-terminal binding. One terminal, one ticket.","Until session ends"],["**Statusline label**","What you see in the terminal chrome.","Refreshes on every render"]],"headers":["Layer","What it is","Lifetime"]}},{"type":"QuoteBlock","props":{"body":"**Ticket drift rule.** When the conversation moves off the active ticket's scope into clearly distinct work, the agent MUST propose closing the current ticket (or marking it review/done) and opening a new one BEFORE responding to the new ask. Never let the statusline lie."}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Cross-persona visibility","eyebrow":"04 — SHARED MEMORY"}},{"type":"P","props":{"body":"All six personas read from the same `memories` table. Filtering is by the `agent` column (or `agent IS NULL` for shared rows). When Atlas writes a learning, Jarvis sees it on next hydration."}},{"type":"P","props":{"body":"**Why this matters:** if {{operator_name}} switches from Atlas's terminal to Ben's, Ben hydrates and immediately knows what Atlas was doing — without {{operator_name}} re-explaining."}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Persona is independent of role","eyebrow":"05 — ROLE vs IDENTITY"}},{"type":"QuoteBlock","props":{"body":"**Persona** = identity (voice, label, color). **Role** = what kind of work the agent does. Today: every persona is an R&D agent (same role, different identity). Tomorrow: Marketing, Sales, Support roles unlock — and persona is independent. Atlas can be R&D today and Marketing later."}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"See the whole picture","eyebrow":"06 — CROSS-LINKS"}},{"type":"P","props":{"body":"Sister diagrams: [System Architecture](/kb-doc/mj-os/system-diagram) · [Data Flows](/kb-doc/mj-os/data-flows) · [Operating Model](/kb-doc/mj-os/operating-model) · [Knowledge Taxonomy](/kb-doc/mj-os/knowledge-taxonomy) · [Persona Stack](/kb-doc/mj-os/persona-stack)."}},{"type":"Footer","props":{"line1":"Persona stack — 6 personas · 1 role today · shared memory · locked 2026-05-13.","line2":"Voice mapping: dashboard remaps OpenAI voice strings → Kokoro IDs server-side in `/api/voice`."}}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- kb-doc/system-standards/knowledge-taxonomy
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$kb-doc/system-standards/knowledge-taxonomy$T$,
  $T${"blocks":[{"type":"Hero","props":{"lede":"A decision tree the agent runs every time new information shows up. Five questions, seven destinations. Tickets, goals, projects, skills, memories, KB pages (classic), KB pages (pitch deck), and Structured pages. Use this to decide where a new note, log, doctrine, or content piece belongs.","title":"MyJarvis — Knowledge Taxonomy · Where does this info go?","eyebrow":"SYSTEM · KNOWLEDGE TAXONOMY"}},{"type":"ImageBlock","props":{"alt":"MyJarvis knowledge taxonomy decision tree","src":"https://{{r2_public_host}}/assets/knowledge-taxonomy-v1-20260513-144358.png","caption":"*Generated 2026-05-13 with Nano Banana. Amber decision pills + color-coded leaf cards (one color per destination).*"}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Where it lands + why","eyebrow":"01 — THE 7 DESTINATIONS"}},{"type":"DataTable","props":{"rows":[["**Ticket**","`tickets` table","Work in progress. ISA-12 sections (Problem, Vision, Goal, Criteria, Decisions, Log).","Markdown columns + ISC checklist"],["**Goal**","`goals` table","Outcome within a project. Body is a recipe.","BlockRenderer recipe (`{blocks: [...]}`)"],["**Project**","`projects` table","Strategic container of goals.","Mission text + status"],["**Skill**","`skills` table (`skill://<slug>`)","Doctrine the agent reads before acting. Required reading for write tools (dashboard skill).","BlockRenderer recipe"],["**Memory**","`memories` table","Session logs, learnings, user facts, areas, principles. Six types.","Markdown"],["**KB page — Classic**","`page_content` at `kb-doc/<slug>`","Editorial content, system maps, decision records, KB articles.","BlockRenderer recipe (`architectureConfig`)"],["**KB page — Pitch**","`page_content` at `pitch-doc/<slug>`","Slide-deck experiences for sales / exec narratives.","BlockRenderer recipe (`pitchDeckConfig`)"],["**Structured page**","Custom React component in `src/`","List, kanban, dashboard, form, index — anything reactive or operational.","Hand-coded TSX"]],"headers":["Destination","Neon table / route","What lives here","Body shape"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"The 5 questions in order","eyebrow":"02 — DECISION TREE"}},{"type":"P","props":{"body":"Walk these top-down. Stop at the first YES."}},{"type":"DataTable","props":{"rows":[["Q1","Is it WORK-IN-PROGRESS — a thing being done?","**Ticket**","go to Q2"],["Q2","Is it an OUTCOME or DELIVERABLE?","**Goal** or **Project**","go to Q3"],["Q3","Is it a RULE the agent must follow when coding?","**Skill**","go to Q4"],["Q4","Is it a SESSION OBSERVATION — learning, fact, log?","**Memory**","go to Q5"],["Q5","Is it long-form CONTENT to be browsed?","**KB page** (Classic *or* Pitch Deck)","**Structured page**"]],"headers":["Q#","Question","YES → ","NO → "]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"See the whole picture","eyebrow":"03 — CROSS-LINKS"}},{"type":"P","props":{"body":"Sister diagrams: [System Architecture](/kb-doc/mj-os/system-diagram) · [Data Flows](/kb-doc/mj-os/data-flows) · [Operating Model](/kb-doc/mj-os/operating-model) · [Knowledge Taxonomy](/kb-doc/mj-os/knowledge-taxonomy) · [Persona Stack](/kb-doc/mj-os/persona-stack)."}},{"type":"Footer","props":{"line1":"Knowledge taxonomy — 7 destinations · 1 root question · locked 2026-05-13.","line2":"Full storage spec: `skill://dashboard` section 06 (Data layer)."}}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- kb-doc/system-standards/data-flows
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$kb-doc/system-standards/data-flows$T$,
  $T${"blocks":[{"type":"Hero","props":{"lede":"Single-image overview of the six core runtime flows. What happens when a session starts, when the agent voices a message, when code ships, when a migration runs, when a page renders, when memory saves. Sibling to the system-architecture diagram — that one is structure, this one is motion.","title":"MyJarvis Dashboard — Data Flows & Processes","eyebrow":"SYSTEM · DATA FLOWS"}},{"type":"ImageBlock","props":{"alt":"MyJarvis Dashboard data flow diagram — six horizontal flows showing session start, voice output, code deploy, DB migration, page render, and memory save.","src":"https://{{r2_public_host}}/assets/dataflow-v1-20260513-143055.png","caption":"*Generated 2026-05-13 with Gemini 2.5 Flash Image (Nano Banana). Six color-coded flows: sky-blue session lifecycle, violet voice, emerald code deploy, amber DB migration, stone-gray page render, warm-red memory save. Exact strings preserved.*"}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Pair with the architecture diagram","eyebrow":"01 — WHAT TO READ NEXT"}},{"type":"P","props":{"body":"This diagram complements [the system architecture diagram](/kb-doc/mj-os/system-diagram). Architecture is the *static* map — what exists. This one is the *dynamic* map — what happens when an event fires."}},{"type":"DataTable","props":{"rows":[["**01 — Session lifecycle**","User opens terminal","Agent hydrated from Neon (agents + tickets + memories), voices greeting"],["**02 — Voice output**","Agent calls `send_voice_message`","Wav generated by Kokoro, lands in R2 + Neon, plays in browser via WebSocket"],["**03 — Code deploy**","Agent calls `write_file` / `push_files`","Preview branch → Cloudflare build → `ship` merges to main"],["**04 — DB migration**","Agent calls `apply_migration`","2-phase: runs on Neon preview branch first, auto-promotes on success"],["**05 — Page render**","User clicks a `/kb-doc/<slug>` route","Pages Function reads `page_content`, BlockRenderer walks the recipe"],["**06 — Memory save**","`SaveSessionMemory` hook fires every 4 turns","Agent writes a `session_log` row to Neon `memories`"]],"headers":["Flow","Trigger","Outcome"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"What's involved","eyebrow":"02 — KEY ACTORS"}},{"type":"P","props":{"body":"Actors that appear across the six flows:"}},{"type":"DataTable","props":{"rows":[["Claude Code (terminal)","Where the agent runs. Hosts the hooks."],["Hooks (`.claude/hooks/`)","UserPromptSubmit / Stop / SessionEnd — fire on lifecycle events. See [/system-diagram](/kb-doc/mj-os/system-diagram) for the full list."],["Agent (Jarvis/Atlas/...)","Persona; reads doctrine via `skill://dashboard`; calls MCP tools to act."],["MCP (my-jarvis-mcp)","Cloudflare Worker; gateway for code/DB/voice/asset operations."],["Cloudflare Pages","Hosts the dashboard frontend + Pages Functions (`/api/*`)."],["Cloudflare Workers + Containers","`my-jarvis-tts-worker` + `KokoroContainer` for Kokoro TTS."],["Neon Postgres","Source of truth: `goals`, `projects`, `tickets`, `agents`, `memories`, `skills`, `page_content`, `voice_samples`, ..."],["R2","Object storage for voice wav files + uploaded assets (diagrams)."],["Durable Objects (WebSocket)","Voice broadcast channel `voice:{user_id}`."],["GitHub","Source repo (`my-jarvis-dashboard-{{tenant_slug}}`). MCP commits to preview branches."],["Browser (AutoplayManager)","Plays voice samples; renders the dashboard."]],"headers":["Actor","Role"]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"See the whole picture","eyebrow":"XX — CROSS-LINKS"}},{"type":"P","props":{"body":"**Sister diagrams in the standards set:** [System Architecture](/kb-doc/mj-os/system-diagram) · [Data Flows](/kb-doc/mj-os/data-flows) · [Operating Model](/kb-doc/mj-os/operating-model) · [Knowledge Taxonomy](/kb-doc/mj-os/knowledge-taxonomy) · [Persona Stack](/kb-doc/mj-os/persona-stack)."}},{"type":"Footer","props":{"line1":"Data flows — locked 2026-05-13. Regenerate if a flow gains/drops a step.","line2":"For per-flow detail, follow the same vocabulary in the dashboard skill (skill://dashboard)."}}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- kb-doc/system-standards/page-inventory
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$kb-doc/system-standards/page-inventory$T$,
  $T${"blocks":[{"type":"Hero","props":{"lede":"Every page on this dashboard, classified against the locked architecture: **Knowledge** (BlockRenderer recipe, default for almost everything), **Structured** (bespoke React pulling specific DB fields — list pages, operator, kanban, animations), or **Unsure** (still hardcoded — needs converting). 113 routes total.","title":"Page inventory — every route, classified","eyebrow":"MJOS-054 · DASHBOARD STANDARDIZATION","subEyebrow":"Live tracking · last updated 2026-05-12"}},{"type":"LivingBanner","props":{"message":"**54** Knowledge (47.8%) · **41** Structured (36.3%) · **15** Unsure (13.3%) · 43 pages converted across 4 waves","pillLabel":"STATE OF PLAY"}},{"type":"SectionHeader","props":{"title":"Conversion timeline — Phase 1 complete: 43 converted, 4 locked Structured, 11 deleted","eyebrow":"00 — STATISTICS"}},{"type":"Grid3","props":{"cards":[{"h4":"43 converted","body":"**43 pages** moved from hardcoded React → Knowledge across 4 waves of parallel subagent dispatch. Each one: read JSX → compose BlockRenderer recipe → INSERT to page_content → replace component with a fetch-and-render shell.","h4ColorToken":"green","accentColorToken":"green"},{"h4":"25 reclassified","body":"**25 pages** moved from Unsure → Structured. 21 reclassified during the 4 conversion waves (slide carousels, kanbans, ReactFlow diagrams, iframe wrappers, Framer Motion, useContentPage edit-flavor). Plus 4 locked at Phase 1 closeout — `/knowledge-base`, `/settings`, `/space-game`, `/youtube-lab` — kept as intentional bespoke React.","h4ColorToken":"skyDark","accentColorToken":"skyDark"},{"h4":"11 deleted","body":"Phase 1 closed 2026-05-13. **11 pages deleted** as dead routes — test pages (`/test-page-01`, `/erez-test-two`, `/mcp-test`), easter eggs (`/pickle-rick`, `/rick-and-morty`), legacy duplicates (`/goals`, `/projects`), unused detail stubs (`/max-case-studies/:slug`, `/questionnaires/:slug`), and superseded surfaces (`/operator-a`, `/meetings/animated-flow`).","h4ColorToken":"red","accentColorToken":"red"}]}},{"type":"DataTable","props":{"rows":[["**Start**","Inventory shipped (MJOS-048)","11","19","80","—","—","`—`"],["**Wave 1**","16 dispatched — migrations / architecture / comparisons / strategy","24","22","64","13","3","`dd48c56, 3a8af67, b3d2825, 224bbb7, 6bf393e, 52c83e9`"],["**Wave 2**","16 dispatched — max-security / max-demos / voice / strategy","35","27","48","11","5","`cf79649, a56a036, b20b2e2, 9e3eaf9, f9730f2, f75ccf0, 8dd1a81, bde3027`"],["**Wave 3**","16 dispatched — business / architecture / ops / weekly","48","30","32","13","3","`b1e3c73, fe42c75, 71ce039, 688989c, c9e9129, c0707b2, 5b3c5ff`"],["**Wave 4**","16 dispatched — sales / decks / discovery / misc","54","41","15","6","10","`5551c30, add3b3b, 561f5e9, 2304826, f9298fb`"],["**Closeout**","Phase 1 standardize sweep — 4 locked Structured, 11 deleted","54","45","0","0","4","`MJOS-054 closeout sweep`"]],"headers":["Wave","What","K","S","U","+Knowledge","→Structured","Commits"]}},{"type":"QuoteBlock","props":{"body":"**Pattern earned:** every Knowledge page now follows the same shape — `<BlockRenderer config={architectureConfig} blocks={recipe} />` rendering a recipe stored in `page_content`. Pages are 30-line shells; content lives in Neon and edits ship without rebuild. The standardize goal Phase 1 conversion playbook is locked: this is the path every dashboard will inherit when we open the per-user template repo. **Phase 1 closed 2026-05-13** — inventory shows zero Unsure pages. Next gate: Phase 2 per-tenant migrate."}},{"type":"TOC","props":{"items":["Summary","How to read this","Knowledge pages","Structured pages","Unsure — closed out","Redirects"]}},{"type":"SectionHeader","props":{"title":"Counts at a glance","eyebrow":"01 — SUMMARY"}},{"type":"Grid3","props":{"cards":[{"h4":"54 Knowledge","body":"Data in any table, layout is a BlockRenderer recipe. The default architecture. Every domain detail page lives here.","h4ColorToken":"green","accentColorToken":"green"},{"h4":"45 Structured","body":"Bespoke React pulling specific DB fields. List pages, operator, kanban. Intentional — the layout is reactive, not a recipe.","h4ColorToken":"skyDark","accentColorToken":"skyDark"},{"h4":"0 Unsure","body":"Phase 1 closed 2026-05-13. All 15 resolved — 4 reclassified Structured (`/knowledge-base`, `/settings`, `/space-game`, `/youtube-lab`); 11 deleted as test/duplicate/dead routes.","h4ColorToken":"green","accentColorToken":"green"}]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Three buckets","eyebrow":"02 — HOW TO READ THIS"}},{"type":"UL","props":{"items":["**Knowledge** — Component imports and renders `<BlockRenderer>`. Recipe may live inline in the TSX, or be loaded from `page_content`, `skills.body`, `tickets.body`, `goals.body`, or `projects.body`. Every detail page should be here.","**Structured** — Component is bespoke React that queries the DB for specific fields and renders a custom layout. List pages (SortableTable + `/api/<resource>`), operator dashboards, kanban boards. Intentional non-Knowledge.","**Unsure** — Component returns hardcoded JSX with no DB and no BlockRenderer. These are the **conversion candidates** — each one should become either Knowledge (most common — move content to `page_content` row + delete the bespoke component) or Structured (if it genuinely needs custom React + DB queries)."]}},{"type":"Divider","props":{}},{"type":"SectionHeader","props":{"title":"Already on the locked architecture (54)","eyebrow":"03 — KNOWLEDGE PAGES"}},{"type":"DataTable","props":{"rows":[["[`/block-library`](/block-library)","`BlockLibraryPage`","Inline recipe — block showcase"],["[`/claude-bedrock-israel`](/claude-bedrock-israel)","`ClaudeBedrockIsraelPage`","Inline recipe"],["[`/dashboard-architecture`](/dashboard-architecture)","`DashboardArchitecturePage`","Inline recipe — architecture doctrine"],["`/goals/:slug`","`GoalDetailPage`","Renders goals.body recipe"],["`/kb-doc/*`","`KbBlueprintPage`","Generic — renders any page_content recipe"],["[`/max-security-eyal-pitch-deck`](/max-security-eyal-pitch-deck)","`MaxSecurityEyalPitchDeckPage`","Inline pitch-deck recipe"],["[`/paperclip-vs-mjos`](/paperclip-vs-mjos)","`PaperclipVsMjosDeckPage`","Inline deck recipe"],["`/projects/:slug`","`ProjectDetailPage`","Renders projects.body recipe"],["`/skills/:slug`","`SkillDetailPage`","Renders skills.body recipe"],["`/tickets/:slug`","`TicketDetailPage`","Renders tickets.body recipe"],["[`/ui-library`](/ui-library)","`UiLibraryPage`","Inline recipe — UI primitives"],["[`/daniel-migration-plan`](/daniel-migration-plan)","`DanielMigrationPlanPage`","Wave 1 (dd48c56) → kb-doc/migrations/daniel, 44 blocks"],["[`/flame-king-mcp-ticket`](/flame-king-mcp-ticket)","`FlameKingMcpTicketPage`","Wave 2 (b20b2e2) → kb-doc/tickets/flame-king-mcp, 46 blocks (pure JSX, inventory note was wrong)"],["[`/agency-architecture`](/agency-architecture)","`AgencyArchitecturePage`","Wave 1 (3a8af67) → kb-doc/architecture/agency, 13 blocks"],["[`/agent-board`](/agent-board)","`AgentBoardPage`","Wave 4 (2304826) → kb-doc/strategy/agent-board, 8 blocks"],["[`/agent-feed-ticket`](/agent-feed-ticket)","`AgentFeedTicketPage`","Wave 4 (2304826) → kb-doc/tickets/agent-feed, 23 blocks"],["[`/ai-news`](/ai-news)","`AINewsPage`","Wave 3 (b1e3c73) → kb-doc/content/ai-news, 9 blocks"],["[`/anthropic-pricing`](/anthropic-pricing)","`AnthropicPricingPage`","Wave 4 (add3b3b) → kb-doc/research/anthropic-pricing, 32 blocks (752-line JSX → 31-line shell)"],["[`/business-blueprint`](/business-blueprint)","`BusinessBlueprintPage`","Wave 3 (b1e3c73) → kb-doc/strategy/business-blueprint, 62 blocks"],["[`/business-blueprint-v1`](/business-blueprint-v1)","`BusinessBlueprintV1Page`","Wave 3 (b1e3c73) → kb-doc/strategy/business-blueprint-v1, 141 blocks (18-section playbook)"],["[`/claude-code-vs-pi`](/claude-code-vs-pi)","`ClaudeCodeVsPiPage`","Wave 1 (b3d2825) → kb-doc/analysis/claude-cod