-- =============================================================
-- Pitch decks — 3 Yaron decks, copied verbatim. The ticket scope
-- explicitly says 'we'll genericize later'. They demonstrate the
-- pitch-doc/* render path; tenants can replace with their own.
-- =============================================================
-- pitch-doc/yaron/welcome
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$pitch-doc/yaron/welcome$T$,
  $T${"blocks":[{"type":"Deck","props":{"audioBase":"https://{{r2_public_host}}/assets/decks/welcome-yaron"},"children":[{"type":"CoverSlide","props":{"sub":"A short tour of what you have just stepped into — from a user experience point of view, no engineering required.","mark":"MyJarvis Dashboard","micro":"Iris · MJOS-063 · five minutes","titleLine1":"Welcome,","titleAccent":"Yaron."}},{"type":"ContentSlide","props":{"lede":"The dashboard is the home base. Voice feed on the right, sidebar on the left, your knowledge in the middle. Everything you touch becomes a row, and every row is something Jarvis, Atlas, Ben, Nova, Emma, or Iris can read or update.","title":"One place | for your work, your context, | and your AI peers.","bullets":[{"body":"Long-running outcomes and the strategic containers that hold them.","title":"Goals & Projects"},{"body":"Atomic work units. One agent, one ticket, one slug, end to end.","title":"Tickets"},{"body":"What we have learned, decided, and the doctrines we follow.","title":"Memory & Skills"}],"chipText":"WHAT THIS IS","chipVariant":"blue"}},{"type":"ContentSlide","props":{"lede":"The voice panel on the right edge of the screen is where every substantive turn lands as audio plus transcript. Six agent personas, each with their own voice and color chip.","title":"Talk to your team. | They reply on the right.","bullets":[{"body":"Open a terminal and start with jarvis, atlas, ben, nova, emma, or iris.","title":"Activate by name"},{"body":"Audio messages live in Neon and R2 — open the tab tomorrow and yesterday is still there.","title":"Persistent feed"},{"body":"Tab open plays live. Tab closed lands in the feed for next time.","title":"Live + replay"}],"chipText":"VOICE FIRST","chipVariant":"blue"}},{"type":"StackSlide","props":{"lede":"Observe what is happening, think before acting, plan, build, execute, verify, learn. The discipline keeps work shippable.","items":[{"num":"01","body":"Read the room. Pull the current state of the world before forming an opinion.","title":"Observe"},{"num":"02","body":"Formulate the shape. Discuss before do, especially for anything non-trivial.","title":"Think"},{"num":"03","body":"Name the criteria for success — each one a single binary probe.","title":"Plan"},{"num":"04","body":"Make the change. Small, atomic, easy to revert.","title":"Build"},{"num":"05","body":"Ship to preview, prove the criteria, then ship to main.","title":"Execute & Verify"},{"num":"06","body":"Distill what was surprising. Memory rows for next time.","title":"Learn"}],"title":"Every ticket walks | the same seven phases.","chipText":"THE FLOW","chipVariant":"blue"}},{"type":"ContentSlide","props":{"lede":"That is the entry point. The hooks open a ticket, the algorithm walks the phases, and you get a paper trail in Neon. Welcome to the calm.","title":"Open a terminal. | Say jarvis and a question.","bullets":[{"body":"Skim /goals-list to see what we are moving toward.","title":"Goals"},{"body":"Open /tickets to see what is in flight.","title":"Tickets"},{"body":"/skills holds the doctrines — read dashboard first.","title":"Skills"}],"chipText":"YOUR NEXT MOVE","chipVariant":"green"}}]}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- pitch-doc/yaron/architecture
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$pitch-doc/yaron/architecture$T$,
  $T${"blocks":[{"type":"Deck","props":{"audioBase":"https://{{r2_public_host}}/assets/decks/architecture-yaron"},"children":[{"type":"CoverSlide","props":{"sub":"A six slide map of the dashboard, the brain, and the voice — the technical companion to the welcome deck.","mark":"MyJarvis Dashboard — Architecture","micro":"Iris · MJOS-063 · six minutes","titleLine1":"How it is","titleAccent":"wired, Yaron."}},{"type":"StackSlide","props":{"lede":"Every part of the system sits in one of these layers. The discipline is keeping them clean.","items":[{"num":"01","body":"Per tenant deploys at my-jarvis-dashboard-{tenant}.pages.dev.","title":"Frontend — Vite plus React on Cloudflare Pages"},{"num":"02","body":"TypeScript, Neon serverless driver, WorkOS AuthKit for auth.","title":"API — Cloudflare Pages Functions"},{"num":"03","body":"Project orange-sky-39481838. Tickets, agents, memories, page content — all in SQL.","title":"Data — Neon Postgres"},{"num":"04","body":"Voice MP3s, images, anything binary. Per tenant bucket on a public r2.dev domain.","title":"Assets — Cloudflare R2"}],"title":"Four layers, | nothing more.","chipText":"THE BIG PICTURE","chipVariant":"blue"}},{"type":"ContentSlide","props":{"lede":"Every page in the dashboard belongs to exactly one. The class of the row decides — narrative content vs. operational data.","title":"Three paths. | Pick the right one. | Do not drift.","bullets":[{"body":"Bespoke React plus useApi. Lists, kanban, dashboards, forms. Reactive surfaces.","title":"Structured"},{"body":"BlockRenderer with architectureConfig. Editorial pages and detail pages for narrative rows.","title":"Knowledge — Classic"},{"body":"BlockRenderer with pitchDeckConfig. This deck you are reading right now.","title":"Knowledge — Pitch deck"}],"chipText":"RENDER PATHS","chipVariant":"plum"}},{"type":"ContentSlide","props":{"lede":"Voice goes through the MyJarvis MCP, into a Cloudflare Worker, into a containerized Kokoro ONNX model, out as WAV to R2, broadcast via a Durable Object WebSocket.","title":"Self hosted Kokoro. | Five dollar a month brain. | No OpenAI dependency.","bullets":[{"body":"What every agent calls to talk to you. Text plus voice plus agent name.","title":"MCP send voice message"},{"body":"Cloudflare hosted, about five times realtime synthesis, fully offline.","title":"TTS Worker plus Container"},{"body":"Tab plays live audio; tab closed lands in the feed for next time.","title":"Durable Object broadcast"}],"chipText":"VOICE STACK","chipVariant":"amber"}},{"type":"StackSlide","props":{"lede":"Preview branch first. Build gate. Ship to main only when green. The MCP enforces the doctrine.","items":[{"num":"01","body":"Atomic commits to a preview branch. Cannot target main directly.","title":"write file and push files"},{"num":"02","body":"Cloudflare Pages build state. Retries if it gets weird, escalates if it cannot.","title":"poll build status"},{"num":"03","body":"Merges preview to main, gated on green build. Auto deploys to production.","title":"ship"},{"num":"04","body":"Two phase Neon migrations: preview branch first, auto promote on success.","title":"apply migration"}],"title":"Every dashboard write | goes through the MCP.","chipText":"MCP DOCTRINE","chipVariant":"green"}},{"type":"QuoteSlide","props":{"quote":"The dashboard is the brain. The terminal is the thin client.","caption":"State lives in Neon, not local files. Memory belongs to all peers. Voice belongs to the user. The whole point is continuity — the next session knows what the last one did, and you can see the paper trail any time.","chipText":"THE PHILOSOPHY","attribution":"MyJarvis OS","chipVariant":"default"}}]}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

-- pitch-doc/yaron/rick-and-morty
INSERT INTO page_content (page_slug, content)
VALUES (
  $T$pitch-doc/yaron/rick-and-morty$T$,
  $T${"blocks":[{"type":"Deck","props":{"audioBase":"https://{{r2_public_host}}/assets/decks/rick-and-morty-quotes"},"children":[{"type":"CoverSlide","props":{"sub":"Ten quotes that range from cosmic to deeply unhelpful. Curated for Yaron because every good dashboard deserves a little nihilism.","mark":"Rick & Morty — ten quotes","micro":"Iris · MJOS-063 · ten slides","titleLine1":"Wisdom from","titleAccent":"a drunk genius."}},{"type":"QuoteSlide","props":{"quote":"Wubba lubba dub dub!","caption":"Bird Person later translated this from the original Birdperson as: 'I am in great pain. Please help me.' So now we know.","chipText":"01 / 10","attribution":"Rick Sanchez","chipVariant":"blue"}},{"type":"QuoteSlide","props":{"quote":"Sometimes science is more art than science.","caption":"The single most useful sentence ever spoken about engineering. Also a great excuse when something doesn't compile.","chipText":"02 / 10","attribution":"Rick Sanchez","chipVariant":"blue"}},{"type":"QuoteSlide","props":{"quote":"Get schwifty in here.","caption":"The official directive when you take off your pants and your panties and you shit on the floor. Recommended state for creative work.","chipText":"03 / 10","attribution":"Rick & Morty","chipVariant":"plum"}},{"type":"QuoteSlide","props":{"quote":"Nothing has any inherent value. We have to give it value.","caption":"Surprisingly load-bearing philosophy for a man who once turned himself into a pickle to avoid family therapy.","chipText":"04 / 10","attribution":"Rick Sanchez","chipVariant":"amber"}},{"type":"QuoteSlide","props":{"quote":"To live is to risk it all. Otherwise you're just an inert chunk of randomly assembled molecules drifting wherever the universe blows you.","caption":"Said in the context of buying a new car. Means more now.","chipText":"05 / 10","attribution":"Rick Sanchez","chipVariant":"green"}},{"type":"QuoteSlide","props":{"quote":"I turned myself into a pickle, Morty! I'm Pickle Riiiiick!","caption":"Possibly the most-quoted sentence of the entire 2010s. Therapy still recommended for whoever wrote that storyline.","chipText":"06 / 10","attribution":"Rick Sanchez","chipVariant":"red"}},{"type":"QuoteSlide","props":{"quote":"Aw geez, Rick.","caption":"An expression of mild panic that has aged into a universal coping mechanism.","chipText":"07 / 10","attribution":"Morty Smith","chipVariant":"blue"}},{"type":"QuoteSlide","props":{"quote":"What is my purpose? — You pass butter. — Oh my god.","caption":"Three sentences that compress the entire AI alignment debate into one breakfast scene.","chipText":"08 / 10","attribution":"Butter Robot & Rick","chipVariant":"amber"}},{"type":"QuoteSlide","props":{"quote":"Existence is pain to a Meeseeks, Jerry, and we will do anything to alleviate that pain.","caption":"If you ever wondered why your AI agents seem desperate to close their tickets, this is the answer.","chipText":"09 / 10","attribution":"Mr. Meeseeks","chipVariant":"plum"}},{"type":"QuoteSlide","props":{"quote":"Don't think about it.","caption":"The most practical advice in the entire show, applied to everything from multiverse paradoxes to whatever Jerry just did.","chipText":"10 / 10","attribution":"Rick Sanchez","chipVariant":"default"}}]}]}$T$::jsonb
)
ON CONFLICT (page_slug) DO NOTHING;

